37: /// Carries some information about the current
38: /// context in which this thread is executed.
39: /// We should strive to have it always accessible
40: /// from ExecContext::CURRENT. Inherits from request
41: /// context for convenience
42: class ExecContext : public RequestContext {
43:   friend struct ExecContextScope;
44:   friend struct ExecContextSuperuserScope;
45: 
46:  protected:
47:   enum class Type { Default, Internal };
48:   class ConstructorToken {};
49: 
50:  public:
51:   ExecContext(ConstructorToken, ExecContext::Type type, std::string const& user,
52:               std::string const& database, auth::Level systemLevel,
53:               auth::Level dbLevel, bool isAdminUser,
54:               std::vector<std::string> const& roles = {},
55:               std::string const& jwtToken = "");
56:   ExecContext(ExecContext const&) = delete;
57:   ExecContext(ExecContext&&) = delete;
58: 
59:  public:
60:   virtual ~ExecContext() = default;
61: 
62:   /// shortcut helper to check the AuthenticationFeature
63:   static bool isAuthEnabled();
64: 
65:   /// Should always contain a reference to current user context
66:   static ExecContext const& current();
67:   /// Note that this intentionally returns CURRENT, even if it is a nullptr:
68:   /// This makes it suitable to set CURRENT in another thread.
69:   static std::shared_ptr<ExecContext const> currentAsShared();
70: 
71:   /// @brief an internal superuser context, is
72:   ///        a singleton instance, deleting is an error
73:   static ExecContext const& superuser();
74:   static std::shared_ptr<ExecContext const> superuserAsShared();
75: 
76:   /// @brief create user context
77:   static std::shared_ptr<ExecContext> create(std::string const& user,
78:                                              std::string const& db);
79: 
80:   /// @brief an internal user is none / ro / rw for all collections / dbs
81:   /// mainly used to override further permission resolution
82:   bool isInternal() const noexcept { return _type == Type::Internal; }
83: 
84:   /// @brief any internal operation is a superuser.
85:   bool isSuperuser() const noexcept {
86:     return isInternal() && _systemDbAuthLevel == auth::Level::RW &&
87:            _databaseAuthLevel == auth::Level::RW;
88:   }
89: 
90:   /// @brief is this an internal read-only user
91:   bool isReadOnly() const noexcept {
92:     return isInternal() && _systemDbAuthLevel == auth::Level::RO;
93:   }
94: 
95:   /// @brief is allowed to manage users, create databases, ...
96:   bool isAdminUser() const noexcept { return _isAdminUser; }
97: 
98:   /// @brief tells you if this execution was canceled
99:   virtual bool isCanceled() const { return false; }
100: 
101:   /// @brief current user, may be empty for internal users
102:   std::string const& user() const { return _user; }
103: 
104:   /// @brief current database
105:   std::string const& database() const { return _database; }
106: 
107:   /// @brief roles from JWT token (if authenticated via JWT)
108:   std::vector<std::string> const& roles() const { return _roles; }
109: 
110:   /// @brief JWT token string (if authenticated via JWT)
111:   std::string const& jwtToken() const { return _jwtToken; }
112: 
113:   /// @brief returns true if authenticated via JWT
114:   bool hasJwtToken() const { return !_jwtToken.empty(); }
115:   /// @brief authentication level on _system. Always RW for superuser
116:   auth::Level systemAuthLevel() const noexcept { return _systemDbAuthLevel; }
117: 
118:   /// @brief Authentication level on database selected in the current
119:   ///        request scope. Should almost always contain something,
120:   ///        if this thread originated in v8 or from HTTP
121:   auth::Level databaseAuthLevel() const noexcept { return _databaseAuthLevel; }
122: 
123:   /// @brief returns true if auth level is above or equal `requested`
124:   bool canUseDatabase(auth::Level requested) const noexcept {
125:     return requested <= _databaseAuthLevel;
126:   }
127: 
128:   /// @brief returns true if auth level is above or equal `requested`
129:   bool canUseDatabase(std::string const& db, auth::Level requested) const;
130: 
131:   /// @brief returns auth level for user
132:   auth::Level collectionAuthLevel(std::string const& dbname,
133:                                   std::string_view collection) const;
134: 
135:   /// @brief returns true if auth levels is above or equal `requested`
136:   bool canUseCollection(std::string const& collection,
137:                         auth::Level requested) const {
138:     return canUseCollection(_database, collection, requested);
139:   }
140:   /// @brief returns true if auth level is above or equal `requested`
141:   bool canUseCollection(std::string const& db, std::string const& coll,
142:                         auth::Level requested) const {
143:     return requested <= collectionAuthLevel(db, coll);
144:   }
145: 
146:   static std::shared_ptr<ExecContext const> set(
147:       std::shared_ptr<ExecContext const> ctx) {
148:     auto tmp = CURRENT;
149:     CURRENT = ctx;
150:     return tmp;
151:   }
152: 
153: #ifdef USE_ENTERPRISE
154:   virtual std::string clientAddress() const { return ""; }
155:   virtual std::string requestUrl() const { return ""; }
156:   virtual std::string authMethod() const { return ""; }
157: #endif
158: 
159:  protected:
160:   /// current user, may be empty for internal users
161:   std::string const _user;
162:   /// current database to use, superuser db is empty
163:   std::string const _database;
164:   /// roles from JWT token (if authenticated via JWT)
165:   std::vector<std::string> const _roles;
166:   /// JWT token string (if authenticated via JWT)
167:   std::string const _jwtToken;
168: 
169:   Type _type;
170:   /// Flag if admin user access (not regarding cluster RO mode)
171:   bool _isAdminUser;
172:   /// level of system database
173:   auth::Level _systemDbAuthLevel;
174:   /// level of current database
175:   auth::Level _databaseAuthLevel;
176: 
177:  private:
178:   static std::shared_ptr<ExecContext const> const Superuser;
179:   static thread_local std::shared_ptr<ExecContext const> CURRENT;
180: };
181: 
182: /// @brief scope guard for the exec context
183: struct ExecContextScope {
184:   explicit ExecContextScope(std::shared_ptr<ExecContext const> exe);
185: 
186:   ~ExecContextScope();
187: 
188:  private:
189:   std::shared_ptr<ExecContext const> _old;
190: };
191: 
192: struct ExecContextSuperuserScope {
193:   explicit ExecContextSuperuserScope() : _old(ExecContext::CURRENT) {
194:     ExecContext::CURRENT = ExecContext::Superuser;
195:   }
196: 
197:   explicit ExecContextSuperuserScope(bool cond) : _old(ExecContext::CURRENT) {
198:     if (cond) {
199:       ExecContext::CURRENT = ExecContext::Superuser;
200:     }
201:   }
202: 
203:   ~ExecContextSuperuserScope() { ExecContext::CURRENT = _old; }
204: 
205:  private:
206:   std::shared_ptr<ExecContext const> _old;
207: };
208: 
209: }  // namespace arangodb
